using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Replace with your actual namespace
using YourNamespace.Data; // Replace with your actual namespace

namespace YourNamespace.Controllers
{
    public class ReviewsController : Controller
    {
        private readonly YourDbContext _context; // Replace with your actual DbContext

        public ReviewsController()
        {
            _context = new YourDbContext(); // Replace with your actual DbContext initialization
        }

        public ActionResult ProductReviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .OrderByDescending(r => r.DateSubmitted)
                .ToList();

            return View(reviews);
        }
    }
}

@model IEnumerable<YourNamespace.Models.Review> <!-- Replace with your actual namespace and model -->

@{
    ViewBag.Title = "Product Reviews";
}

<h2>Product Reviews</h2>

@foreach (var review in Model)
{
    <div class="review">
        <p><strong>@review.UserName</strong> - @review.DateSubmitted.ToShortDateString()</p>
        <div>@Html.Raw(review.Content)</div>
    </div>
}